// Colors for Inspirando Padres client
const IP = {
  turquoise: "#00A99D",
  yellow:    "#FFD100",
  pink:      "#fc8ecf",
};

const INITIAL_TASKS = [
  // SEMANA 1 - COMPLETADA
  { id: 1, week: 1, phase: "Infraestructura", task: "Auditoría técnica del dominio y hosting", owner: "Dmente Digital", status: "done", priority: "high", notes: "Namecheap + Hostinger verificados" },
  { id: 2, week: 1, phase: "Infraestructura", task: "Adquisición dominio en Namecheap", owner: "Grace", status: "done", priority: "high", notes: "Dominio activo ✓" },
  { id: 3, week: 1, phase: "Infraestructura", task: "Configuración Hosting Hostinger", owner: "Grace", status: "done", priority: "high", notes: "Hosting operacional ✓" },
  { id: 4, week: 1, phase: "Infraestructura", task: "Creación correo corporativo info@inspirandopadres.com", owner: "Dmente Digital", status: "done", priority: "high", notes: "Correo operacional ✓" },

  // SEMANA 2 - EN PROGRESO
  { id: 5, week: 2, phase: "DNS & Systeme.io", task: "Grace agrega Dmente Digital como Admin en Systeme.io", owner: "Grace", status: "pending", priority: "high", notes: "BLOQUEANTE para avanzar" },
  { id: 6, week: 2, phase: "DNS & Systeme.io", task: "Ejecutar 'Add Manager' en Namecheap", owner: "Grace", status: "pending", priority: "high", notes: "Compartir acceso vía Add Manager" },
  { id: 7, week: 2, phase: "DNS & Systeme.io", task: "Cambio Nameservers Namecheap → Hostinger (ns1/ns2.dns-parking.com)", owner: "Dmente Digital", status: "pending", priority: "high", notes: "Requiere acceso de Grace primero" },
  { id: 8, week: 2, phase: "DNS & Systeme.io", task: "Validar registros CNAME en Systeme.io", owner: "Dmente Digital", status: "pending", priority: "high", notes: "Post configuración DNS" },
  { id: 9, week: 2, phase: "Diseño Landing", task: "Revisión 3 diseños de Landing Page propuestos", owner: "Grace", status: "pending", priority: "medium", notes: "Ver mockup en Drive y dar feedback por WhatsApp" },
  { id: 10, week: 2, phase: "Diseño Landing", task: "Diseño Landing eBook #1 (colores manual + copy de Grace)", owner: "Dmente Digital", status: "in-progress", priority: "high", notes: "Entregar versión final en 2-3 días" },
  { id: 11, week: 2, phase: "Contenido", task: "Grace crea Mini eBook gancho (Lead Magnet)", owner: "Grace", status: "pending", priority: "high", notes: "Versión rápida para este fin de semana" },
  { id: 12, week: 2, phase: "Contenido", task: "Grace sube links Hotmart y perfiles RRSS a Drive", owner: "Grace", status: "pending", priority: "medium", notes: "Incluir LinkedIn" },
  { id: 13, week: 2, phase: "Contenido", task: "Aprobación cronograma semanal de redes sociales", owner: "Grace", status: "pending", priority: "medium", notes: "Lun/Mié/Vie/Dom — ver plan semana" },

  // SEMANA 3
  { id: 14, week: 3, phase: "Automatización", task: "Configurar automatización envío Mini eBook desde info@inspirandopadres.com", owner: "Dmente Digital", status: "pending", priority: "high", notes: "Vía Systeme.io" },
  { id: 15, week: 3, phase: "Automatización", task: "Configurar pasarelas de pago (Hotmart)", owner: "Dmente Digital", status: "pending", priority: "high", notes: "Regla de los 3 minutos — entrega inmediata" },
  { id: 16, week: 3, phase: "Automatización", task: "Flujo de correos automáticos post-compra (CRM)", owner: "Dmente Digital", status: "pending", priority: "high", notes: "Invitación al curso online / talleres Bogotá" },
  { id: 17, week: 3, phase: "Landing", task: "Landing eBook #2 con Order Bump", owner: "Dmente Digital", status: "pending", priority: "medium", notes: "Precio $11 USD + bump segundo producto" },

  // SEMANA 4
  { id: 18, week: 4, phase: "Lanzamiento", task: "Lanzamiento piloto controlado", owner: "Dmente Digital + Grace", status: "pending", priority: "high", notes: "Monitoreo comisión 20%" },
  { id: 19, week: 4, phase: "Lanzamiento", task: "Monitoreo tasa de conversión Landing Page", owner: "Dmente Digital", status: "pending", priority: "high", notes: "Objetivo: validar funnel" },
  { id: 20, week: 4, phase: "Lanzamiento", task: "Primera charla en vivo (Instagram/YouTube)", owner: "Grace + Hija", status: "pending", priority: "medium", notes: "Dmente propone fecha y canal" },

  // B2B
  { id: 21, week: 2, phase: "B2B", task: "Scrapping LinkedIn + Google Maps — Directores de colegios", owner: "Dmente Digital", status: "pending", priority: "medium", notes: "Base de datos para prospección B2B" },
  { id: 22, week: 2, phase: "B2B", task: "Explorar landing rápida Escuela de Artistas (Paula / Min. Cultura)", owner: "Dmente Digital", status: "pending", priority: "low", notes: "Proyecto paralelo" },
];

const STATUS_CONFIG = {
  done:        { label: "Completado",   color: C.dmenteCyan,    bg: `${C.dmenteCyan}18` },
  "in-progress":{ label: "En Progreso", color: C.yellow || "#FFD100", bg: `${C.dataSkyBlue}18` },
  pending:     { label: "Pendiente",    color: C.muted,         bg: `${C.muted}22` },
  blocked:     { label: "Bloqueado",    color: C.dmenteMagenta, bg: `${C.dmenteMagenta}18` },
};

const PRIORITY_CONFIG = {
  high:   { label: "Alta",  color: C.dmenteMagenta },
  medium: { label: "Media", color: "#FFD100" },
  low:    { label: "Baja",  color: C.muted },
};

const WEEKS = [1, 2, 3, 4];
const WEEK_LABELS = {
  1: "Semana 1 — Infraestructura",
  2: "Semana 2 — DNS, Diseño & Contenido",
  3: "Semana 3 — Automatización & Pagos",
  4: "Semana 4 — Lanzamiento Piloto",
};

function DmenteLogo({ size = 36 }) {
  return (
    <img
      src={LOGO_B64}
      alt="Dmente Digital"
      style={{ width: size, height: size, borderRadius: 8, objectFit: "cover", objectPosition: "center" }}
    />
  );
}

function Tag({ color, children, style: s = {} }) {
  return (
    <span style={{
      display: "inline-block",
      background: `${color}18`,
      border: `1px solid ${color}40`,
      color,
      fontSize: 10,
      fontWeight: 700,
      letterSpacing: "0.16em",
      padding: "3px 10px",
      borderRadius: 20,
      fontFamily: F,
      textTransform: "uppercase",
      ...s,
    }}>{children}</span>
  );
}

export default function Tracker() {
  const [tasks, setTasks] = useState(() => {
    try {
      const saved = localStorage.getItem("ip_tracker_tasks");
      return saved ? JSON.parse(saved) : INITIAL_TASKS;
    } catch { return INITIAL_TASKS; }
  });
  const [activeWeek, setActiveWeek] = useState("all");
  const [editingId, setEditingId] = useState(null);
  const [editNotes, setEditNotes] = useState("");
  const [showAddModal, setShowAddModal] = useState(false);
  const [newTask, setNewTask] = useState({ week: 2, phase: "", task: "", owner: "", status: "pending", priority: "medium", notes: "" });

  useEffect(() => {
    try { localStorage.setItem("ip_tracker_tasks", JSON.stringify(tasks)); } catch {}
  }, [tasks]);

  const filtered = activeWeek === "all" ? tasks : tasks.filter(t => t.week === activeWeek);

  const stats = {
    total: tasks.length,
    done: tasks.filter(t => t.status === "done").length,
    inProgress: tasks.filter(t => t.status === "in-progress").length,
    pending: tasks.filter(t => t.status === "pending").length,
    blocked: tasks.filter(t => t.status === "blocked").length,
  };
  const pct = Math.round((stats.done / stats.total) * 100);

  function updateStatus(id, status) {
    setTasks(prev => prev.map(t => t.id === id ? { ...t, status } : t));
  }

  function saveNotes(id) {
    setTasks(prev => prev.map(t => t.id === id ? { ...t, notes: editNotes } : t));
    setEditingId(null);
  }

  function addTask() {
    const id = Math.max(...tasks.map(t => t.id)) + 1;
    setTasks(prev => [...prev, { ...newTask, id }]);
    setShowAddModal(false);
    setNewTask({ week: 2, phase: "", task: "", owner: "", status: "pending", priority: "medium", notes: "" });
  }

  function deleteTask(id) {
    setTasks(prev => prev.filter(t => t.id !== id));
  }

  const inputStyle = {
    background: `${C.deepSpace}cc`,
    border: `1px solid rgba(43,235,210,0.2)`,
    borderRadius: 8,
    color: C.ghostWhite,
    fontFamily: F,
    fontSize: 12,
    padding: "8px 12px",
    outline: "none",
    width: "100%",
  };

  return (
    <div style={{ background: C.deepSpace, minHeight: "100vh", fontFamily: F, color: C.ghostWhite }}>
      {/* Google Fonts */}
      <style>{`@import url('https://fonts.googleapis.com/css2?family=Plus+Jakarta+Sans:wght@300;400;500;600;700;800&display=swap');
      * { box-sizing: border-box; }
      ::-webkit-scrollbar { width: 4px; } ::-webkit-scrollbar-track { background: ${C.deepSpace}; } ::-webkit-scrollbar-thumb { background: ${C.growthEmerald}; border-radius: 4px; }
      select option { background: ${C.logicIndigo}; color: ${C.ghostWhite}; }
      `}</style>

      {/* HEADER */}
      <div style={{
        background: `linear-gradient(135deg, ${C.logicIndigo} 0%, ${C.deepSpace} 100%)`,
        borderBottom: `1px solid rgba(43,235,210,0.1)`,
        padding: "32px 40px 28px",
        position: "relative",
        overflow: "hidden",
      }}>
        {/* Grid */}
        <div style={{ position: "absolute", inset: 0, pointerEvents: "none",
          backgroundImage: `linear-gradient(rgba(43,235,210,0.025) 1px, transparent 1px), linear-gradient(90deg, rgba(43,235,210,0.025) 1px, transparent 1px)`,
          backgroundSize: "44px 44px",
        }}/>
        {/* Glow */}
        <div style={{ position: "absolute", top: -80, right: -80, width: 320, height: 320, borderRadius: "50%",
          background: `radial-gradient(circle, ${C.growthEmerald}22 0%, transparent 70%)`, pointerEvents: "none" }}/>
        <div style={{ position: "absolute", bottom: -60, left: 200, width: 200, height: 200, borderRadius: "50%",
          background: `radial-gradient(circle, ${IP.turquoise}18 0%, transparent 70%)`, pointerEvents: "none" }}/>

        <div style={{ position: "relative", display: "flex", justifyContent: "space-between", alignItems: "flex-start", flexWrap: "wrap", gap: 20 }}>
          {/* Left: Agency + Project */}
          <div>
            <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 16 }}>
              <DmenteLogo size={44} />
              <div>
                <div style={{ fontSize: 11, fontWeight: 700, color: C.dmenteCyan, letterSpacing: "0.18em" }}>DMENTE DIGITAL</div>
                <div style={{ fontSize: 10, color: C.muted, fontStyle: "italic" }}>No es azar, es propósito</div>
              </div>
            </div>
            <Tag color={IP.turquoise} style={{ marginBottom: 10 }}>FASE PILOTO 2026 · CONFIDENCIAL</Tag>
            <div style={{ display: "flex", alignItems: "center", gap: 12, marginTop: 8 }}>
              <div style={{ width: 8, height: 8, borderRadius: "50%", background: IP.turquoise, boxShadow: `0 0 8px ${IP.turquoise}` }}/>
              <h1 style={{ margin: 0, fontSize: 28, fontWeight: 800, letterSpacing: "-0.03em", color: C.ghostWhite }}>
                Inspirando Padres
                <span style={{ color: C.dmenteCyan }}> · Tracker</span>
              </h1>
            </div>
            <div style={{ fontSize: 13, color: C.mutedLight, marginTop: 6 }}>
              Plan Estratégico de Marketing y Diferenciación — 30 días
            </div>
          </div>

          {/* Right: Client card */}
          <div style={{
            background: `${C.logicIndigo}cc`, border: `1px solid ${IP.turquoise}30`,
            borderRadius: 16, padding: "16px 20px", backdropFilter: "blur(12px)", minWidth: 180,
            borderTop: `3px solid ${IP.turquoise}`,
          }}>
            <div style={{ fontSize: 10, color: C.muted, letterSpacing: "0.15em", marginBottom: 8 }}>CLIENTE</div>
            <div style={{ fontSize: 15, fontWeight: 800, color: IP.turquoise }}>Grace Cardona</div>
            <div style={{ fontSize: 11, color: C.mutedLight, marginTop: 2 }}>Inspirando Padres</div>
            <div style={{ borderTop: `1px solid rgba(43,235,210,0.1)`, marginTop: 10, paddingTop: 8 }}>
              <div style={{ fontSize: 10, color: C.muted }}>Comisión: <span style={{ color: IP.yellow, fontWeight: 700 }}>20% ventas netas</span></div>
              <div style={{ fontSize: 10, color: C.muted, marginTop: 3 }}>info@inspirandopadres.com</div>
            </div>
          </div>
        </div>

        {/* Progress bar */}
        <div style={{ position: "relative", marginTop: 28 }}>
          <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 8, flexWrap: "wrap", gap: 8 }}>
            {[
              { label: "Completadas", val: stats.done, color: C.dmenteCyan },
              { label: "En Progreso", val: stats.inProgress, color: "#FFD100" },
              { label: "Pendientes",  val: stats.pending, color: C.muted },
              { label: "Bloqueadas",  val: stats.blocked, color: C.dmenteMagenta },
            ].map(s => (
              <div key={s.label} style={{ display: "flex", alignItems: "center", gap: 6 }}>
                <div style={{ width: 8, height: 8, borderRadius: "50%", background: s.color }}/>
                <span style={{ fontSize: 11, color: C.mutedLight }}>{s.label}: <strong style={{ color: s.color }}>{s.val}</strong></span>
              </div>
            ))}
            <span style={{ fontSize: 11, color: C.dmenteCyan, fontWeight: 700, marginLeft: "auto" }}>{pct}% completado</span>
          </div>
          <div style={{ height: 6, background: `${C.logicIndigo}`, borderRadius: 3, overflow: "hidden" }}>
            <div style={{ height: "100%", width: `${pct}%`, background: `linear-gradient(90deg, ${C.growthEmerald}, ${C.dmenteCyan})`, borderRadius: 3, transition: "width 0.5s ease" }}/>
          </div>
        </div>
      </div>

      {/* TOOLBAR */}
      <div style={{ padding: "20px 40px", display: "flex", alignItems: "center", gap: 12, flexWrap: "wrap", borderBottom: `1px solid rgba(43,235,210,0.06)` }}>
        {/* Week tabs */}
        {["all", ...WEEKS].map(w => (
          <button key={w} onClick={() => setActiveWeek(w)} style={{
            background: activeWeek === w ? `${C.dmenteCyan}18` : "transparent",
            border: `1px solid ${activeWeek === w ? C.dmenteCyan : "rgba(43,235,210,0.15)"}`,
            color: activeWeek === w ? C.dmenteCyan : C.mutedLight,
            borderRadius: 8, padding: "6px 16px", fontSize: 11, fontWeight: 700,
            letterSpacing: "0.1em", cursor: "pointer", fontFamily: F,
            textTransform: "uppercase",
          }}>
            {w === "all" ? "Todas" : `S${w}`}
          </button>
        ))}
        <div style={{ flex: 1 }}/>
        <button onClick={() => setShowAddModal(true)} style={{
          background: `${C.dmenteCyan}22`, border: `1px solid ${C.dmenteCyan}50`,
          color: C.dmenteCyan, borderRadius: 8, padding: "6px 18px",
          fontSize: 11, fontWeight: 700, letterSpacing: "0.12em", cursor: "pointer", fontFamily: F,
        }}>+ AGREGAR TAREA</button>
      </div>

      {/* TASKS */}
      <div style={{ padding: "24px 40px 40px" }}>
        {(activeWeek === "all" ? WEEKS : [activeWeek]).map(week => {
          const weekTasks = filtered.filter(t => t.week === week);
          if (!weekTasks.length) return null;
          const wDone = weekTasks.filter(t => t.status === "done").length;
          const wPct = Math.round((wDone / weekTasks.length) * 100);
          return (
            <div key={week} style={{ marginBottom: 32 }}>
              {/* Week header */}
              <div style={{ display: "flex", alignItems: "center", gap: 14, marginBottom: 16 }}>
                <div style={{ width: 28, height: 28, borderRadius: "50%", background: week === 1 ? C.dmenteCyan : `${C.growthEmerald}44`,
                  border: `2px solid ${week === 1 ? C.dmenteCyan : C.growthEmerald}`, display: "flex", alignItems: "center", justifyContent: "center",
                  fontSize: 11, fontWeight: 800, color: week === 1 ? C.deepSpace : C.dmenteCyan }}>{week}</div>
                <h2 style={{ margin: 0, fontSize: 14, fontWeight: 700, color: C.ghostWhite, letterSpacing: "0.05em" }}>{WEEK_LABELS[week]}</h2>
                {week === 1 && <Tag color={C.dmenteCyan}>COMPLETADA ✓</Tag>}
                {week === 2 && <Tag color="#FFD100">EN CURSO</Tag>}
                <span style={{ fontSize: 11, color: C.muted, marginLeft: "auto" }}>{wDone}/{weekTasks.length} · {wPct}%</span>
              </div>

              {/* Task rows */}
              <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
                {weekTasks.map(task => {
                  const sc = STATUS_CONFIG[task.status];
                  const pc = PRIORITY_CONFIG[task.priority];
                  const isEditing = editingId === task.id;
                  return (
                    <div key={task.id} style={{
                      background: C.logicIndigo,
                      border: `1px solid rgba(43,235,210,0.08)`,
                      borderLeft: `3px solid ${sc.color}`,
                      borderRadius: 12,
                      padding: "14px 18px",
                      display: "grid",
                      gridTemplateColumns: "1fr auto",
                      gap: 12,
                      alignItems: "center",
                    }}>
                      <div>
                        {/* Phase + priority */}
                        <div style={{ display: "flex", gap: 6, marginBottom: 6, flexWrap: "wrap" }}>
                          <Tag color={IP.turquoise}>{task.phase}</Tag>
                          <Tag color={pc.color}>{pc.label}</Tag>
                        </div>
                        {/* Task name */}
                        <div style={{ fontSize: 14, fontWeight: 600, color: task.status === "done" ? C.muted : C.ghostWhite,
                          textDecoration: task.status === "done" ? "line-through" : "none", marginBottom: 4 }}>
                          {task.task}
                        </div>
                        {/* Owner */}
                        <div style={{ fontSize: 11, color: C.mutedLight }}>
                          👤 <span style={{ color: C.dataSkyBlue }}>{task.owner}</span>
                        </div>
                        {/* Notes */}
                        {isEditing ? (
                          <div style={{ marginTop: 8, display: "flex", gap: 8 }}>
                            <input value={editNotes} onChange={e => setEditNotes(e.target.value)}
                              style={{ ...inputStyle, flex: 1 }} placeholder="Notas..." />
                            <button onClick={() => saveNotes(task.id)} style={{
                              background: `${C.dmenteCyan}22`, border: `1px solid ${C.dmenteCyan}50`,
                              color: C.dmenteCyan, borderRadius: 6, padding: "4px 12px", fontSize: 11, cursor: "pointer", fontFamily: F }}>Guardar</button>
                            <button onClick={() => setEditingId(null)} style={{
                              background: "transparent", border: `1px solid ${C.muted}40`,
                              color: C.muted, borderRadius: 6, padding: "4px 10px", fontSize: 11, cursor: "pointer", fontFamily: F }}>✕</button>
                          </div>
                        ) : task.notes ? (
                          <div onClick={() => { setEditingId(task.id); setEditNotes(task.notes); }}
                            style={{ fontSize: 11, color: C.muted, marginTop: 6, cursor: "text",
                              padding: "4px 8px", borderRadius: 6, background: `${C.deepSpace}80`,
                              display: "inline-block" }}>
                            💬 {task.notes}
                          </div>
                        ) : (
                          <div onClick={() => { setEditingId(task.id); setEditNotes(""); }}
                            style={{ fontSize: 11, color: `${C.muted}60`, marginTop: 6, cursor: "text" }}>
                            + agregar nota
                          </div>
                        )}
                      </div>

                      {/* Right controls */}
                      <div style={{ display: "flex", flexDirection: "column", alignItems: "flex-end", gap: 8 }}>
                        <select value={task.status} onChange={e => updateStatus(task.id, e.target.value)}
                          style={{ ...inputStyle, width: "auto", fontSize: 11, padding: "5px 10px",
                            color: sc.color, borderColor: `${sc.color}40`, background: sc.bg }}>
                          {Object.entries(STATUS_CONFIG).map(([k, v]) => (
                            <option key={k} value={k}>{v.label}</option>
                          ))}
                        </select>
                        <button onClick={() => deleteTask(task.id)} style={{
                          background: "transparent", border: "none", color: `${C.muted}60`,
                          cursor: "pointer", fontSize: 12, padding: "2px 4px" }} title="Eliminar">🗑</button>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          );
        })}
      </div>

      {/* ADD MODAL */}
      {showAddModal && (
        <div style={{ position: "fixed", inset: 0, background: "rgba(6,20,33,0.92)", display: "flex", alignItems: "center", justifyContent: "center", zIndex: 100, padding: 20 }}>
          <div style={{ background: C.logicIndigo, border: `1px solid rgba(43,235,210,0.2)`, borderRadius: 20, padding: 32, width: "100%", maxWidth: 480 }}>
            <h3 style={{ margin: "0 0 20px", fontSize: 16, fontWeight: 800, color: C.dmenteCyan }}>Nueva Tarea</h3>
            {[
              { label: "Fase / Categoría", key: "phase", type: "text", ph: "ej: DNS & Systeme.io" },
              { label: "Tarea", key: "task", type: "text", ph: "Descripción de la tarea" },
              { label: "Responsable", key: "owner", type: "text", ph: "ej: Dmente Digital" },
              { label: "Notas", key: "notes", type: "text", ph: "Observaciones opcionales" },
            ].map(f => (
              <div key={f.key} style={{ marginBottom: 14 }}>
                <label style={{ fontSize: 10, color: C.muted, letterSpacing: "0.15em", fontWeight: 700, display: "block", marginBottom: 6 }}>{f.label.toUpperCase()}</label>
                <input value={newTask[f.key]} onChange={e => setNewTask(p => ({ ...p, [f.key]: e.target.value }))}
                  style={inputStyle} placeholder={f.ph} />
              </div>
            ))}
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 12, marginBottom: 20 }}>
              <div>
                <label style={{ fontSize: 10, color: C.muted, letterSpacing: "0.15em", fontWeight: 700, display: "block", marginBottom: 6 }}>SEMANA</label>
                <select value={newTask.week} onChange={e => setNewTask(p => ({ ...p, week: Number(e.target.value) }))} style={inputStyle}>
                  {WEEKS.map(w => <option key={w} value={w}>Semana {w}</option>)}
                </select>
              </div>
              <div>
                <label style={{ fontSize: 10, color: C.muted, letterSpacing: "0.15em", fontWeight: 700, display: "block", marginBottom: 6 }}>ESTADO</label>
                <select value={newTask.status} onChange={e => setNewTask(p => ({ ...p, status: e.target.value }))} style={inputStyle}>
                  {Object.entries(STATUS_CONFIG).map(([k, v]) => <option key={k} value={k}>{v.label}</option>)}
                </select>
              </div>
              <div>
                <label style={{ fontSize: 10, color: C.muted, letterSpacing: "0.15em", fontWeight: 700, display: "block", marginBottom: 6 }}>PRIORIDAD</label>
                <select value={newTask.priority} onChange={e => setNewTask(p => ({ ...p, priority: e.target.value }))} style={inputStyle}>
                  {Object.entries(PRIORITY_CONFIG).map(([k, v]) => <option key={k} value={k}>{v.label}</option>)}
                </select>
              </div>
            </div>
            <div style={{ display: "flex", gap: 10, justifyContent: "flex-end" }}>
              <button onClick={() => setShowAddModal(false)} style={{
                background: "transparent", border: `1px solid ${C.muted}40`, color: C.muted,
                borderRadius: 8, padding: "8px 20px", fontSize: 12, cursor: "pointer", fontFamily: F }}>Cancelar</button>
              <button onClick={addTask} disabled={!newTask.task || !newTask.phase} style={{
                background: `${C.dmenteCyan}22`, border: `1px solid ${C.dmenteCyan}60`,
                color: C.dmenteCyan, borderRadius: 8, padding: "8px 24px",
                fontSize: 12, fontWeight: 700, cursor: "pointer", fontFamily: F,
                opacity: (!newTask.task || !newTask.phase) ? 0.4 : 1 }}>Agregar Tarea</button>
            </div>
          </div>
        </div>
      )}

      {/* FOOTER */}
      <div style={{ borderTop: `1px solid rgba(43,235,210,0.07)`, padding: "20px 40px",
        display: "flex", justifyContent: "space-between", alignItems: "center", flexWrap: "wrap", gap: 12 }}>
        <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
          <DmenteLogo size={28} />
          <div>
            <div style={{ fontSize: 11, fontWeight: 700, color: C.dmenteCyan, letterSpacing: "0.06em" }}>DMENTE DIGITAL × INSPIRANDO PADRES</div>
            <div style={{ fontSize: 10, color: C.muted, fontStyle: "italic" }}>No es azar, es propósito · CONFIDENCIAL 2026</div>
          </div>
        </div>
        <div style={{ display: "flex", flexDirection: "column", alignItems: "flex-end", gap: 2 }}>
          <a href="https://www.dmentedigital.co" target="_blank" rel="noreferrer"
            style={{ fontSize: 11, color: C.dataSkyBlue, textDecoration: "none", fontWeight: 600 }}>www.dmentedigital.co</a>
          <span style={{ fontSize: 10, color: C.muted, letterSpacing: "0.1em" }}>© 2026 DMENTE DIGITAL</span>
        </div>
      </div>
    </div>
  );
}
